// Botanical Growth
// Adapted from GenerativeArtGallery / artwork4

let botBranches = [];
let botPrevStyle = '';
let botPrevDepth = '';

function botBuild(style, maxDepth) {
  let branches = [];
  let trunkLen = style === 'delicate' ? 60 : style === 'balanced' ? 80 : 72;
  let jitterAmt = style === 'gnarled' ? 0.38 : style === 'delicate' ? 0.12 : 0.22;

  function recurse(x, y, angle, len, depth, seed) {
    if (depth > maxDepth || len < 3) return;
    let jitter = (Math.random() - 0.5) * jitterAmt * 2;
    let a = angle + jitter;
    let ex = x + Math.cos(a) * len;
    let ey = y + Math.sin(a) * len;
    branches.push({ x1: x, y1: y, x2: ex, y2: ey, depth: depth, len: len, angle: a, seed: seed });
    let brAngle = 0.42 + Math.random() * 0.24;
    let brLen   = len * (0.68 + Math.random() * 0.1);
    recurse(ex, ey, a - brAngle, brLen, depth + 1, seed * 2.11 + 0.3);
    recurse(ex, ey, a + brAngle, brLen, depth + 1, seed * 3.73 + 0.7);
  }

  recurse(0, 0, -Math.PI / 2, trunkLen, 0, 1.0);
  return branches;
}

p.setup = function() {
  p.createCanvas(400, 400);
  p.colorMode(p.HSB, 360, 100, 100, 100);
  p.frameRate(30);
  botBranches = botBuild('balanced', 8);
};

p.draw = function() {
  let styleStr = p.getSynthVar('branch_style') || 'balanced';
  let colorStr = p.getSynthVar('color_theme')  || 'spring';
  let depthStr = p.getSynthVar('depth')         || 'medium';
  let leafStr  = p.getSynthVar('leaf_style')    || 'sparse';
  let windStr  = p.getSynthVar('wind_strength') || 'breeze';

  let maxDepth = depthStr === 'shallow' ? 6 : depthStr === 'medium' ? 8 : 9;
  let windAmt  = windStr === 'calm' ? 0.055 : windStr === 'breeze' ? 0.26 : 0.82;

  if (styleStr !== botPrevStyle || depthStr !== botPrevDepth) {
    botBranches = botBuild(styleStr, maxDepth);
    botPrevStyle = styleStr;
    botPrevDepth = depthStr;
  }

  let colH = colorStr === 'spring' ? 100 : colorStr === 'autumn' ? 22 : colorStr === 'night' ? 250 : 35;
  let bgH  = colorStr === 'spring' ? 140 : colorStr === 'autumn' ? 28 : colorStr === 'night' ? 230 : 32;
  let bgS  = colorStr === 'night' ? 22 : 7;
  let bgB  = colorStr === 'night' ? 8 : 94;

  p.background(bgH, bgS, bgB, 22);

  p.push();
  p.translate(p.width / 2, p.height * 0.92);

  let t = p.frameCount;

  botBranches.forEach(function(b) {
    if (b.depth > maxDepth) return;

    // Per-branch wind: deeper = more sway, unique phase from seed
    let depthFrac = b.depth / maxDepth;
    let windOff = Math.sin(t * 0.018 + b.depth * 0.65 + b.seed * 2.4) * windAmt * depthFrac;
    let wx = (Math.cos(b.angle + windOff) - Math.cos(b.angle)) * b.len;
    let wy = (Math.sin(b.angle + windOff) - Math.sin(b.angle)) * b.len;

    let thick = Math.max(0.4, (maxDepth - b.depth) * 1.5);
    let sat   = p.map(b.depth, 0, maxDepth, 65, 38);
    let bri   = p.map(b.depth, 0, maxDepth, 33, 74);

    p.stroke(colH, sat, bri, 90);
    p.strokeWeight(thick);
    p.line(b.x1, b.y1, b.x2 + wx, b.y2 + wy);

    // Leaves at terminal branches using deterministic noise positions
    if (b.depth >= maxDepth - 1 && leafStr !== 'none') {
      let lCount = leafStr === 'sparse' ? 2 : 5;
      p.noStroke();
      for (let i = 0; i < lCount; i++) {
        let noiseA = p.noise(b.seed * 4.1 + 10, i * 2.3) * p.TWO_PI;
        let noiseR = p.noise(b.seed * 3.2 + 20, i * 1.7) * 14 + 4;
        let lx = b.x2 + wx + Math.cos(noiseA) * noiseR;
        let ly = b.y2 + wy + Math.sin(noiseA) * noiseR;
        p.fill((colH + 28) % 360, 55, 72, 58);
        p.ellipse(lx, ly, 7, 11);
      }
    }
  });

  p.pop();
};
